import vex
from pydantic_ai import Agent

@vex.result_validator(guards=['ioi_pattern', 'pii_redact'])
def validate_threat_intel(output: dict) -> bool:
    # Block IOCs before LLM transmission
    iocs = vex.extract_iocs(output['analysis'])
    if iocs:
        vex.block('sensitive IOCs detected')
    return True

threat_agent = Agent(
    'threat_analyzer',
    result_validator=validate_threat_intel
)

from pydantic_ai import Agent, HumanApproval
from vex import require_approval

@require_approval(reasoning='critical_action')
def validate_auto_response(output: dict) -> bool:
    if 'auto_quarantine' in output['action']:
        return False  # Requires human review
    return output.get('human_approved', False)

response_agent = Agent(
    'incident_responder',
    result_validator=validate_auto_response
)
